def get_maxgold(gold, m, n):
    dp = [[0 for _ in range(n)] for _ in range(m)]
    for col in range(n-1, -1, -1):
        for row in range(m):
            if col == n-1:
                dp[row][col] = gold[row][col]
            else:
                if row > 0:
                    dp[row][col] = gold[row][col] + max(dp[row-1][col+1], dp[row][col+1])
                elif row < m-1:
                    dp[row][col] = gold[row][col] + max(dp[row][col+1], dp[row+1][col+1])
                else:
                    dp[row][col] = gold[row][col] + dp[row][col+1]
    return max(dp[i][0] for i in range(m))

